  origin: ['https://www.roofmanager.ca', 'https://roofmanager.ca', 'http://localhost:3000', 'http://0.0.0.0:3000'],
  allowMethods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
