// ============================================================
// OG IMAGE FALLBACK — /og/:slug.svg
// Blog posts without a cover_image_url get a branded 1200x630 SVG with
// the title rendered. SVG is valid for og:image on Google SERP + AI
// crawlers. Social platforms fallback to static logo when needed.
// ============================================================
app.get('/og/:filename', async (c) => {
  const filename = c.req.param('filename')
  if (!filename.endsWith('.svg')) return c.notFound()
  const slug = filename.slice(0, -4)
  try {
    const post = await c.env.DB.prepare(
      `SELECT title, category FROM blog_posts WHERE slug = ? AND status = 'published'`,
    ).bind(slug).first<{ title: string; category: string | null }>()
    const title = post?.title || 'Roof Manager'
    const category = (post?.category || 'roofing').replace(/-/g, ' ')
    // Break title into ~2 visual lines (roughly ≤38 chars each) for readability
    const words = title.split(/\s+/)
    const lines: string[] = []
    let cur = ''
    for (const w of words) {
      if ((cur + ' ' + w).trim().length > 38 && cur) { lines.push(cur); cur = w }
      else cur = (cur + ' ' + w).trim()
    }
    if (cur) lines.push(cur)
    const displayLines = lines.slice(0, 3)
    const esc = (s: string) => s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    const svg = `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 1200 630" width="1200" height="630">
  <defs>
    <linearGradient id="bg" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0" stop-color="#0A0A0A"/>
      <stop offset="1" stop-color="#0f172a"/>
    </linearGradient>
  </defs>
  <rect width="1200" height="630" fill="url(#bg)"/>
  <rect x="0" y="0" width="1200" height="6" fill="#00FF88"/>
  <text x="80" y="100" font-family="Inter, system-ui, sans-serif" font-size="22" font-weight="700" fill="#00FF88" letter-spacing="4">ROOF MANAGER</text>
  <text x="80" y="140" font-family="Inter, system-ui, sans-serif" font-size="18" fill="#9ca3af" letter-spacing="2">${esc(category.toUpperCase())}</text>
  ${displayLines.map((ln, i) => `<text x="80" y="${260 + i * 80}" font-family="Inter, system-ui, sans-serif" font-size="64" font-weight="800" fill="#ffffff">${esc(ln)}</text>`).join('\n  ')}
  <text x="80" y="560" font-family="Inter, system-ui, sans-serif" font-size="20" fill="#9ca3af">www.roofmanager.ca  &#8226;  Satellite roof measurement &amp; CRM</text>
</svg>`
    return c.body(svg, 200, {
      'Content-Type': 'image/svg+xml; charset=utf-8',
      'Cache-Control': 'public, max-age=86400, s-maxage=86400',
    })
  } catch {
    return c.notFound()
  }
})

// ============================================================
// EXPORT — Cloudflare Workers module with fetch + scheduled handlers
// ============================================================
export default {
  // Standard HTTP handler — delegates to Hono app
  fetch: app.fetch,

  // Scheduled (CRON) handler — Autonomous Agent Hub
  // All 5 agents are gated by their agent_configs.enabled flag.
  // Tracing: every cron tick | Content: 8am UTC | Lead: every 2h | Email: Tuesdays 10am UTC | Monitor: every 6h
  async scheduled(event: ScheduledEvent, env: Bindings, ctx: ExecutionContext) {
    const now = new Date()
    const hour = now.getUTCHours()
    const dayOfWeek = now.getUTCDay() // 0=Sun, 2=Tue

    // Helper: check agent_configs.enabled for a given agent type
    async function isAgentEnabled(agentType: string): Promise<boolean> {
      const row = await env.DB.prepare(
        `SELECT enabled FROM agent_configs WHERE agent_type = ?`
      ).bind(agentType).first<{ enabled: number }>()
      return row?.enabled === 1
    }

    // Helper: log run result to agent_runs + update agent_configs stats
    async function logRun(agentType: string, status: string, summary: string, details: any, durationMs: number) {
      try {
        await env.DB.prepare(
          `INSERT INTO agent_runs (agent_type, status, summary, details_json, duration_ms) VALUES (?, ?, ?, ?, ?)`
        ).bind(agentType, status, summary, JSON.stringify(details).slice(0, 4000), durationMs).run()
        await env.DB.prepare(
          `UPDATE agent_configs SET last_run_at=datetime('now'), last_run_status=?, last_run_details=?,
           run_count=run_count+1, error_count=error_count+CASE WHEN ?='error' THEN 1 ELSE 0 END,
           updated_at=datetime('now') WHERE agent_type=?`
        ).bind(status, summary.slice(0, 500), status, agentType).run()
      } catch {}
    }

    // ── Tracing Agent (every cron tick) ──────────────────────
    if (await isAgentEnabled('tracing')) {
      ctx.waitUntil((async () => {
        const t0 = Date.now()
        try {
          const result = await processOrderQueue(env)
          const summary = `Processed ${result.processed.length} order(s)`
          console.log(`[CRON:tracing] ${summary}`)
          await logRun('tracing', 'success', summary, result.stats, Date.now() - t0)
        } catch (err: any) {
          console.error('[CRON:tracing] Error:', err.message)
          await logRun('tracing', 'error', err.message, {}, Date.now() - t0)
        }
      })())
    }

    // ── Content Agent (daily at 8am UTC) ─────────────────────
    if (hour === 8 && await isAgentEnabled('content')) {
      ctx.waitUntil((async () => {
        const t0 = Date.now()
        try {
          const result = await runContentAgent(env)
          const summary = result.skipped ? 'No keywords in queue'
            : result.ok ? `Published "${result.keyword}" (q=${result.quality?.overall}%)`
            : `Failed: ${result.error}`
          console.log(`[CRON:content] ${summary}`)
          await logRun('content', result.ok ? 'success' : (result.skipped ? 'skipped' : 'error'), summary, result, Date.now() - t0)
        } catch (err: any) {
          console.error('[CRON:content] Error:', err.message)
          await logRun('content', 'error', err.message, {}, Date.now() - t0)
        }
      })())
    }

    // ── Lead Agent (every 2 hours) ────────────────────────────
    if (hour % 2 === 0 && await isAgentEnabled('lead')) {
      ctx.waitUntil((async () => {
        const t0 = Date.now()
        try {
          const result = await runLeadAgent(env)
          const summary = result.responded === 0 ? 'No new leads'
            : `Responded to ${result.responded} lead(s)`
          console.log(`[CRON:lead] ${summary}`)
          await logRun('lead', result.ok ? 'success' : 'error', summary, result, Date.now() - t0)
        } catch (err: any) {
          console.error('[CRON:lead] Error:', err.message)
          await logRun('lead', 'error', err.message, {}, Date.now() - t0)
        }
      })())
    }

    // ── Email Agent (Tuesdays at 10am UTC) ───────────────────
    if (dayOfWeek === 2 && hour === 10 && await isAgentEnabled('email')) {
      ctx.waitUntil((async () => {
        const t0 = Date.now()
        try {
          const result = await runEmailAgent(env)
          const summary = result.skipped ? 'No contacts to email'
            : result.ok ? `Sent "${result.campaign_name}" to ${result.sent} contact(s)`
            : `Failed: ${result.errors[0]}`
          console.log(`[CRON:email] ${summary}`)
          await logRun('email', result.ok ? 'success' : (result.skipped ? 'skipped' : 'error'), summary, result, Date.now() - t0)
        } catch (err: any) {
          console.error('[CRON:email] Error:', err.message)
          await logRun('email', 'error', err.message, {}, Date.now() - t0)
        }
      })())
    }

    // ── Monitor Agent (every 6 hours: 0, 6, 12, 18 UTC) ──────
    if (hour % 6 === 0 && await isAgentEnabled('monitor')) {
      ctx.waitUntil((async () => {
        const t0 = Date.now()
        try {
          const result = await runMonitorAgent(env)
          const summary = `Health ${result.health_score}/100 — ${result.issues_found} finding(s)${result.critical_count > 0 ? ` (${result.critical_count} critical!)` : ''}`
          console.log(`[CRON:monitor] ${summary}`)
          await logRun('monitor', result.ok ? 'success' : 'error', summary, { health_score: result.health_score, issues_found: result.issues_found }, Date.now() - t0)
        } catch (err: any) {
          console.error('[CRON:monitor] Error:', err.message)
          await logRun('monitor', 'error', err.message, {}, Date.now() - t0)
        }
      })())
    }

    // Loop Tracker scanners moved to src/cron-worker.ts. Cloudflare Pages
    // does not honor scheduled() handlers in the Pages Function — only the
    // separate roofmanager-agent-cron Worker fires on cron. Keeping the
    // logic here was a no-op that masked the cron breakage for weeks.

    // ── Traffic Analyst Agent (every 12 hours: 0, 12 UTC) ────
    if (hour % 12 === 0 && await isAgentEnabled('traffic')) {
      ctx.waitUntil((async () => {
        const t0 = Date.now()
        try {
          const result = await runTrafficAgent(env)
          const summary = result.sessions_analyzed === 0 ? 'No visitor sessions to analyze'
            : result.insights_found === 0 ? `Analyzed ${result.sessions_analyzed} session(s) — no new findings`
            : `Analyzed ${result.sessions_analyzed} sessions — ${result.insights_found} UX finding(s), ${result.bounce_rate_pct}% bounce rate`
          console.log(`[CRON:traffic] ${summary}`)
          await logRun('traffic', result.ok ? (result.sessions_analyzed < 3 ? 'skipped' : 'success') : 'error', summary, { sessions_analyzed: result.sessions_analyzed, insights_found: result.insights_found }, Date.now() - t0)
        } catch (err: any) {
          console.error('[CRON:traffic] Error:', err.message)
          await logRun('traffic', 'error', err.message, {}, Date.now() - t0)
        }
      })())
    }

    // ── User Activity rollup ─────────────────────────────────
    // Runs every hour. The rollup is idempotent (ON CONFLICT DO UPDATE
    // on user_activity_daily, idempotent purge on user_module_visits),
    // so an hourly catch-up means a single missed cron tick can't lose
    // a day's data. Cost is negligible — 2 small queries.
    ctx.waitUntil((async () => {
      try {
        const result = await activityRollupYesterday(env)
        if (result.rolled || result.purged) {
          console.log(`[CRON:activity] rolled=${result.rolled} purged=${result.purged}`)
        }
      } catch (err: any) {
        console.error('[CRON:activity] Error:', err.message)
      }
    })())

    // ── Auth cleanup (every cron tick) ───────────────────────
    // Phase 3 #9: replaces the inline fire-and-forget DELETEs that used to
    // piggyback on /login and /forgot-password. Each DELETE is a single
    // index-bounded scan and is safe to retry, so an hourly tick is more
    // than enough to keep these tables tidy without paying latency on every
    // request. Errors are logged loudly here (no more silent swallow).
    ctx.waitUntil((async () => {
      try {
        const sessions = await env.DB.prepare(
          "DELETE FROM customer_sessions WHERE expires_at < datetime('now')"
        ).run()
        const adminSessions = await env.DB.prepare(
          "DELETE FROM admin_sessions WHERE expires_at < datetime('now')"
        ).run()
        const codes = await env.DB.prepare(
          "DELETE FROM email_verification_codes WHERE expires_at < datetime('now') AND used = 1"
        ).run()
        const resets = await env.DB.prepare(
          "DELETE FROM password_reset_tokens WHERE (expires_at < datetime('now') OR used = 1) AND created_at < datetime('now', '-1 day')"
        ).run()
        const totals = {
          customer_sessions: (sessions?.meta as any)?.changes ?? 0,
          admin_sessions: (adminSessions?.meta as any)?.changes ?? 0,
          email_verification_codes: (codes?.meta as any)?.changes ?? 0,
          password_reset_tokens: (resets?.meta as any)?.changes ?? 0,
        }
        const total = totals.customer_sessions + totals.admin_sessions + totals.email_verification_codes + totals.password_reset_tokens
        if (total > 0) {
          console.log(`[CRON:auth-cleanup] purged ${JSON.stringify(totals)}`)
        }
      } catch (err: any) {
        console.error('[CRON:auth-cleanup] Error:', err?.message || err)
      }
    })())

  },
}

