function getOnboardingPageHTML(sessionToken = ''): string {
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width,initial-scale=1">
  <title>Welcome to Roof Manager — Get Started</title>
  <link rel="icon" href="/static/favicon.ico?v=20260504">
  <link rel="stylesheet" href="/static/tailwind.css">
  <style>
    body { background:#0A0A0A; color:#fff; font-family:'Inter',sans-serif; }
    .step { display:none; }
    .step.active { display:block; }
    .progress-dot { width:10px; height:10px; border-radius:50%; background:rgba(255,255,255,0.2); transition:background 0.3s; }
    .progress-dot.done { background:#00FF88; }
    .progress-dot.active { background:#00FF88; box-shadow:0 0 0 4px rgba(0,255,136,0.2); }
  </style>
</head>
<body class="min-h-screen flex flex-col">
  <!-- Header -->
  <header class="flex items-center justify-between px-6 py-4 border-b border-white/10">
    <a href="/" class="flex items-center gap-2 text-white font-black text-xl">
      <img src="/static/logo.svg?v=20260504" alt="Roof Manager" class="h-8 w-8" onerror="this.style.display='none'">
      Roof Manager
    </a>
    <a href="/customer/dashboard" class="text-sm text-gray-400 hover:text-white">Skip setup &rarr;</a>
  </header>

  <main class="flex-1 flex flex-col items-center justify-center px-4 py-12">
    <!-- Progress dots -->
    <div class="flex items-center gap-3 mb-10" id="progress-dots">
      <div class="progress-dot active" id="dot-1"></div>
      <div class="w-8 h-px bg-white/20"></div>
      <div class="progress-dot" id="dot-2"></div>
      <div class="w-8 h-px bg-white/20"></div>
      <div class="progress-dot" id="dot-3"></div>
    </div>

    <div class="w-full max-w-lg">

      <!-- Step 1: Welcome -->
      <div class="step active" id="step-1">
        <div class="text-center mb-8">
          <div style="font-size:56px;margin-bottom:12px">&#x1F3E0;</div>
          <h1 class="text-3xl font-black mb-3">Welcome to Roof Manager!</h1>
          <p class="text-gray-400 text-lg">Let's get your account set up in under 2 minutes.<br>You have <span class="text-[#00FF88] font-bold">4 free reports</span> ready to use.</p>
        </div>
        <div style="background:#111111;border:1px solid rgba(255,255,255,0.08);border-radius:16px;padding:24px;margin-bottom:24px">
          <h3 class="font-bold text-white mb-3 text-sm uppercase tracking-wider">What you can do right now:</h3>
          <ul class="space-y-3">
            <li class="flex items-start gap-3 text-sm text-gray-300"><span style="color:#00FF88;font-size:18px">&#x2713;</span>Generate a precise roof measurement report</li>
            <li class="flex items-start gap-3 text-sm text-gray-300"><span style="color:#00FF88;font-size:18px">&#x2713;</span>Manage customers, jobs, and invoices from one dashboard</li>
            <li class="flex items-start gap-3 text-sm text-gray-300"><span style="color:#00FF88;font-size:18px">&#x2713;</span>Send professional proposals and track deal status</li>
          </ul>
        </div>
        <button onclick="nextStep(1)" style="width:100%;padding:16px;background:#00FF88;color:#0A0A0A;font-weight:800;border:none;border-radius:12px;font-size:17px;cursor:pointer">
          Let's go &#x2192;
        </button>
      </div>

      <!-- Step 2: Company name -->
      <div class="step" id="step-2">
        <div class="text-center mb-8">
          <div style="font-size:48px;margin-bottom:12px">&#x1F3D7;&#xFE0F;</div>
          <h2 class="text-2xl font-black mb-2">What's your company name?</h2>
          <p class="text-gray-400">This will appear on your reports and proposals.</p>
        </div>
        <input type="text" id="company-name" placeholder="e.g. Smith Roofing Ltd."
          style="width:100%;padding:16px 18px;background:#111111;border:1.5px solid rgba(255,255,255,0.15);border-radius:12px;color:#fff;font-size:16px;margin-bottom:16px;box-sizing:border-box;outline:none"
          onfocus="this.style.borderColor='#00FF88'" onblur="this.style.borderColor='rgba(255,255,255,0.15)'">
        <label for="company-phone" style="display:block;font-size:13px;color:#9ca3af;margin-bottom:6px">Phone number <span style="color:#00FF88">*</span></label>
        <input type="tel" id="company-phone" required inputmode="tel" autocomplete="tel" placeholder="(403) 555-0100"
          style="width:100%;padding:16px 18px;background:#111111;border:1.5px solid rgba(255,255,255,0.15);border-radius:12px;color:#fff;font-size:16px;margin-bottom:8px;box-sizing:border-box;outline:none"
          onfocus="this.style.borderColor='#00FF88'" onblur="this.style.borderColor='rgba(255,255,255,0.15)'">
        <p id="step-2-error" style="display:none;color:#f87171;font-size:13px;margin:0 0 12px"></p>
        <button onclick="saveCompany()" style="width:100%;padding:16px;background:#00FF88;color:#0A0A0A;font-weight:800;border:none;border-radius:12px;font-size:17px;cursor:pointer">
          Continue &#x2192;
        </button>
      </div>

      <!-- Step 3: Done -->
      <div class="step" id="step-3">
        <div class="text-center">
          <div style="font-size:72px;margin-bottom:16px">&#x1F389;</div>
          <h2 class="text-3xl font-black mb-3">You're all set!</h2>
          <p class="text-gray-400 text-lg mb-8">Your account is ready. Head to your dashboard to start managing jobs and generating reports.</p>
          <a href="/customer/dashboard" style="display:inline-block;padding:16px 40px;background:#00FF88;color:#0A0A0A;font-weight:800;border-radius:12px;font-size:17px;text-decoration:none">
            Go to Dashboard &#x2192;
          </a>
          <div style="margin-top:24px">
            <a href="/customer/order" style="color:#00CC6A;font-size:14px;text-decoration:none">Or create a report now &#x2192;</a>
          </div>
        </div>
      </div>

    </div>
  </main>

  <script>
  var currentStep = 1;
  var sessionToken = '${sessionToken}';

  // Restore token from localStorage if not passed in URL
  if (!sessionToken) {
    sessionToken = localStorage.getItem('rc_customer_token') || '';
  }

  // Resume from the persisted onboarding_step on the customer record so a
  // user who closed the tab mid-flow doesn't have to start over.
  function authHeaders() {
    return sessionToken
      ? { 'Authorization': 'Bearer ' + sessionToken, 'Content-Type': 'application/json' }
      : { 'Content-Type': 'application/json' };
  }

  async function loadResumeState() {
    if (!sessionToken) return;
    try {
      var r = await fetch('/api/customer-auth/profile', { headers: authHeaders() });
      if (!r.ok) return;
      var j = await r.json().catch(function(){ return {}; });
      var c = j && j.customer;
      if (!c) return;
      // If they already finished, send them straight to the dashboard.
      if (c.onboarding_completed) { window.location.replace('/customer/dashboard'); return; }
      var resumeStep = Math.max(1, Math.min(3, (c.onboarding_step || 0) + 1));
      if (resumeStep > 1) jumpToStep(resumeStep);
    } catch (_) { /* network glitch — start at step 1 */ }
  }

  function jumpToStep(target) {
    if (target < 1 || target > 3) return;
    for (var i = 1; i <= 3; i++) {
      var el = document.getElementById('step-' + i);
      var dot = document.getElementById('dot-' + i);
      if (el) el.classList.toggle('active', i === target);
      if (dot) {
        dot.classList.toggle('active', i === target);
        dot.classList.toggle('done', i < target);
      }
    }
    currentStep = target;
  }

  function trackStep(step, action) {
    if (!sessionToken) return;
    try {
      fetch('/api/customer-auth/onboarding/track', {
        method: 'POST', headers: authHeaders(),
        body: JSON.stringify({ step: step, action: action || 'completed' })
      }).catch(function(){});
    } catch(_) {}
  }

  function nextStep(from, action) {
    trackStep(from, action || 'completed');
    var el = document.getElementById('step-' + from);
    if (el) el.classList.remove('active');
    var dot = document.getElementById('dot-' + from);
    if (dot) { dot.classList.remove('active'); dot.classList.add('done'); }
    currentStep = from + 1;
    var next = document.getElementById('step-' + currentStep);
    if (next) next.classList.add('active');
    var nextDot = document.getElementById('dot-' + currentStep);
    if (nextDot) nextDot.classList.add('active');
    // When the user lands on the final step, mark onboarding complete so the
    // "Welcome back, finish setup" banner doesn't reappear on the dashboard.
    // Server requires step >= 4 to flip onboarding_completed; pass 4 explicitly
    // even though the wizard's UI only has 3 visible steps.
    if (currentStep === 3) trackStep(4, 'completed');
  }

  async function saveCompany() {
    var name = (document.getElementById('company-name').value || '').trim();
    var phone = (document.getElementById('company-phone').value || '').trim();
    var errEl = document.getElementById('step-2-error');
    function showErr(msg) {
      if (!errEl) return;
      errEl.textContent = msg; errEl.style.display = 'block';
    }
    if (errEl) { errEl.textContent = ''; errEl.style.display = 'none'; }
    if (!phone || phone.replace(/\D/g, '').length < 7) {
      showErr('Please enter a valid phone number to continue.');
      var phEl = document.getElementById('company-phone'); if (phEl) phEl.focus();
      return;
    }
    if (sessionToken) {
      try {
        var res = await fetch('/api/customer/profile', {
          method: 'PUT',
          headers: authHeaders(),
          body: JSON.stringify({ company_name: name, phone: phone })
        });
        if (!res.ok) { showErr('Could not save your details — please try again.'); return; }
      } catch(e) { showErr('Network error saving details — please try again.'); return; }
    }
    nextStep(2);
  }

  loadResumeState();
  </script>
</body>
</html>`
}

function getMagicLinkErrorHTML(message: string): string {
  return `<!DOCTYPE html><html><head><title>Link expired</title></head><body style="font-family:sans-serif;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;background:#f9fafb">
    <div style="text-align:center;padding:32px;max-width:400px">
      <div style="font-size:48px;margin-bottom:16px">&#x1F517;</div>
      <h2 style="color:#0A0A0A;margin-bottom:8px">Link expired</h2>
      <p style="color:#6b7280;margin-bottom:24px">${message}</p>
      <a href="/customer/login" style="background:#00FF88;color:#0A0A0A;font-weight:700;padding:12px 24px;border-radius:10px;text-decoration:none">Request a new link</a>
    </div>
  </body></html>`
}

function getPasswordResetFormHTML(token: string): string {
  return `<!DOCTYPE html><html><head><title>Reset password \u2014 Roof Manager</title></head>
  <body style="font-family:sans-serif;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;background:#f9fafb">
    <div style="width:100%;max-width:400px;padding:32px;background:#fff;border-radius:16px;box-shadow:0 4px 24px rgba(0,0,0,0.06)">
      <h2 style="margin-bottom:20px;color:#0A0A0A">Set new password</h2>
      <input type="password" id="new-pw" placeholder="New password (min 8 chars)" minlength="8" data-clarity-mask="true"
        style="width:100%;padding:12px 16px;border:1.5px solid #d1d5db;border-radius:10px;font-size:15px;margin-bottom:12px;box-sizing:border-box">
      <input type="password" id="confirm-pw" placeholder="Confirm new password" minlength="8" data-clarity-mask="true"
        style="width:100%;padding:12px 16px;border:1.5px solid #d1d5db;border-radius:10px;font-size:15px;margin-bottom:16px;box-sizing:border-box">
      <div id="reset-error" style="display:none;color:#ef4444;font-size:14px;margin-bottom:12px"></div>
      <button onclick="doReset()" style="width:100%;padding:14px;background:#00FF88;color:#0A0A0A;font-weight:800;border:none;border-radius:10px;font-size:16px;cursor:pointer">
        Set new password
      </button>
    </div>
    <script>
    async function doReset() {
      var pw = document.getElementById('new-pw').value;
      var conf = document.getElementById('confirm-pw').value;
      if (pw !== conf) { document.getElementById('reset-error').textContent = 'Passwords do not match.'; document.getElementById('reset-error').style.display='block'; return; }
      if (pw.length < 8) { document.getElementById('reset-error').textContent = 'Password must be at least 8 characters.'; document.getElementById('reset-error').style.display='block'; return; }
      var res = await fetch('/api/customer/reset-password', {
        method: 'POST', headers: {'Content-Type':'application/json'},
        body: JSON.stringify({token: '${token}', new_password: pw})
      });
      var data = await res.json();
      if (data.success) { window.location.href = '/customer/login'; }
      else { document.getElementById('reset-error').textContent = data.error || 'Reset failed.'; document.getElementById('reset-error').style.display='block'; }
    }
    </script>
  </body></html>`
}

