          <div class="inline-flex items-center gap-2 bg-[#00FF88]/10 text-[#00FF88] rounded-full px-4 py-1.5 text-sm font-semibold mb-6"><i class="fas fa-map-marker-alt"></i> ${city.name}, ${city.province}</div>
